solution_code:
#include <iostream>
#include <cmath>

int safeRoot(int x) {
    return static_cast<int>(std::sqrt(static_cast<double>(x)));
}

void safeRoot(double) = delete;

int main() {
    int n;
    std::cin >> n;
    std::cout << "Root: " << safeRoot(n) << "\n";
    return 0;
}
